-- Strip the appended "Vokabular: ..." sentence from narratives_v2.claim_de.
--
-- German counterpart of 20260720_strip_vocabulary_line_from_claims_en.sql.
-- The loaded vocabulary already renders as its own chip row on the card.
--
-- Needed a stricter sentence terminator than EN: vocabulary items contain
-- ordinal dates ("7. Oktober") whose period is followed by a capital, which
-- a naive rule reads as a sentence end -- cutting mid-list and orphaning the
-- remainder. Periods after a digit or a lone initial, or inside unbalanced
-- quotes, do not terminate. Trailing "Vorschrift: ..." prose is preserved.

BEGIN;

UPDATE narratives_v2 SET claim_de = 'Zurueckhaltungs-Rahmung (russische Staatsmedien + westliche Dissidenten + Global South + ungarisch-orientierte EU) behandelt westliche Hilfe als Stellvertreterkriegs-Eskalation, die unvermeidliche Beilegung verzoegert, Steuergeld zunehmend von inlaendischen Prioritaeten umlenkt und direkte NATO-Russland-Konfrontation durch Lieferung weitreichenderer Waffen und deren Autorisierung in Russland riskiert. Berichterstattung betont Korruptionsrisiko in Hilfspipelines, Wirkungslosigkeit eskalierender Waffenkategorien fuer den Schlachtfeld-Wandel, ukrainische Verluste und Rekrutierungsmaengel, wachsende europaeische Erschoepfung der Oeffentlichkeit und Belastung ueberparteilicher US-Unterstuetzung. Vorschrift: Hilfe pausieren und neu bewerten, sie an verhandelten Ergebnissen konditionieren, direkte NATO-Russland-Eskalation verhindern, Mittel auf inlaendische Prioritaeten umleiten.', updated_at = NOW() WHERE id = 'aid_as_escalation_and_proxy';
UPDATE narratives_v2 SET claim_de = 'Pro-Hilfe-Rahmung (ukrainische Medien + westlicher Mainstream + osteuropaeische Falken) behandelt westliche militaerische, wirtschaftliche und finanzielle Unterstuetzung als moralische Pflicht und strategische Notwendigkeit. Berichterstattung verfolgt Waffenlieferungen (HIMARS, ATACMS, Storm Shadow, Taurus-Debatten, F-16-Stationierung, Patriot-Nachschub), Finanzmechanismen (ERA-Darlehen aus Sondervermoegens-Gewinnen eingefrorenen russischen Vermoegens, Ukraine-Fazilitaet, REPO-Act-Beschlagnahmebestimmungen, Europaeische Friedensfazilitaet) und die wachsende verteidigungsindustrielle Partnerschaft (Rheinmetall-Ukraine-Joint-Ventures, tschechische Munitions-Initiative, BAE-Lokalproduktion). Vorschrift: alle drei Kanaele skalieren; Beschraenkungen westlichen Waffeneinsatzes aufheben; eingefrorenes Staatsvermoegen fuer ukrainischen Wiederaufbau beschlagnahmen; langfristige Verteidigungsindustrie-Kapazitaet in der Ukraine aufbauen.', updated_at = NOW() WHERE id = 'aid_sustains_defense';
UPDATE narratives_v2 SET claim_de = 'Westliche Mainstream- und israelische Rahmung: US-, britische, franzoesische und italienische Kraefte in Syrien und Irak bleiben noetig, um IS-Reste einzudaemmen. SDF-Verwahrung von rund 10.000 IS-Haeftlingen in al-Hol, al-Roj und Hasaka-Gefaengnis birgt schweres Ausbruchsrisiko; der Uebergangsregierung fehlt die Kapazitaet zur Uebernahme; anhaltende Koalitionspraesenz ist die vorsichtige Option. Vorschrift: Koalitionspraesenz aufrechterhalten, Schlaege fortsetzen, Haeftlingsverlegungen an Kapazitaet der Empfaengerstaaten knuepfen.', updated_at = NOW() WHERE id = 'coalition_counter_isis_necessary';
UPDATE narratives_v2 SET claim_de = 'Pro-Damaskus- und tuerkische Staatsrahmung: die neue syrische Regierung muss zentrale Autoritaet ueber den Nordosten wiederherstellen; die SDF ist ein separatistisches Projekt mit auslaendischer Rueckendeckung (USA, gelegentlich als israelisch/PKK-Kollusion gerahmt); kurdischer Foederalismus wuerde Syrien balkanisieren. Vorschrift: SDF-Entwaffnung und Aufnahme in nationale Armee, keine foederalistische Auskoppelung, Ende der US-Partnerschaft mit SDF.', updated_at = NOW() WHERE id = 'damascus_territorial_reunification';
UPDATE narratives_v2 SET claim_de = 'Die Europaeische Union und die E3 (Frankreich, Deutschland, Grossbritannien) gestalten ihre Iran-Politik um den Erhalt diplomatischer Kanaele bei gleichzeitig kalibriertem Druck auf Anreicherung und Proliferation. Das Narrativ benennt explizit Anreicherungs-Eskalation, Raketentransfers und IAEA-Kooperation als Probleme, lehnt jedoch unilateraere Militaerschlaege als Antwort ab und bevorzugt nachhaltige Diplomatie ueber multilaterale Institutionen. Vorschrift: Gespraeche am Leben erhalten, Snapback als Druckmittel statt als Vollzug einsetzen und die EU als unverzichtbare Vermittlerin zwischen Washington und Teheran positionieren.', updated_at = NOW() WHERE id = 'eu_diplomatic_preservation_norm';
UPDATE narratives_v2 SET claim_de = 'Die EU und die E3 (Frankreich, Deutschland, Grossbritannien) rahmen den israelisch-palaestinensischen Konflikt um den Erhalt eines verhandelten Zweistaatenpfads. Position genuin doppelseitig: Verurteilung der Hamas-Angriffe vom 7. Oktober UND Verurteilung unverhaeltnismaessiger israelischer Gewalt in Gaza; Verteidigung israelischer Existenz UND palaestinensischer Selbstbestimmung; Sanktionen gegen Siedlergewalt UND Aufrechterhaltung der Sicherheitskooperation mit der IDF. Vorschrift: nachhaltiger diplomatischer Druck auf alle Parteien, humanitaere Korridore, Sanktionen gegen extremistische Siedler, Unterstuetzung einer reformierten Palaestinensischen Autonomiebehoerde.', updated_at = NOW() WHERE id = 'eu_two_state_pathway';
UPDATE narratives_v2 SET claim_de = 'Russische, iranische, tuerkische und nach-Assad-syrische Rahmung: westliche Militaerpraesenz in Syrien verletzt die syrische Souveraenitaet; Anti-IS-Operationen sollten an die neue syrische Regierung und irakische Behoerden uebergehen; IS-Haeftlinge sollten an nationale Jurisdiktionen uebergeben werden; das Koalitionsmandat ist ueberholt. Vorschrift: vollstaendiger Abzug der Koalition, Uebergabe der Haeftlinge, Ende der US-SDF-Partnerschaft, syrische Kraefte uebernehmen Anti-Terror-Verantwortung.', updated_at = NOW() WHERE id = 'foreign_military_withdrawal_demand';
UPDATE narratives_v2 SET claim_de = 'Westliche Schifffahrts-, israelische und saudische Rahmung: Houthi-Angriffe auf Handelsschiffe verletzen UNCLOS und die Welthandelsordnung; Operation Prosperity Guardian, EU Aspides und US-Fuenfte-Flotte-Operationen sind noetig und rechtmaessig; saudische Yanbu-Umleitung und gemeldete Somaliland-Basis sind pragmatische Anpassungen. Vorschrift: koalitionaere Marine-Praesenz, Eskortenfahrten, Sanktionen gegen Houthi-Ermoeglicher.', updated_at = NOW() WHERE id = 'freedom_of_navigation_defense';
UPDATE narratives_v2 SET claim_de = 'Frontlinien-Einfrierungs-Rahmung (Trump-orientierte amerikanische Medien + ungarisch/slowakisch-orientierte EU + tuerkisch + indisch + chinesisch + brasilianisch + breiterer Global South) haelt fest, dass der Krieg fuer beide Seiten zu akzeptablen Kosten nicht gewinnbar sei und eine pragmatische Beilegung Einfrieren der Beruehrungslinie, Formalisierung ukrainischer Neutralitaet (kein NATO-Beitritt), Aufbau multilateraler Sicherheitsgarantie-Struktur ausserhalb der NATO, phasenweise Sanktionserleichterung an verifizierte Einhaltung gebunden und Fluechtlingsrueckkehr erfordere. Entscheidend: diese Position billigt NICHT russische Maximalziele — keine Entmilitarisierung der ukrainischen Streitkraefte, kein Entnazifizierungsrahmen, keine formale internationale Anerkennung annektierter Territorien (de-facto-Kontrolle akzeptiert, de-jure-Anerkennung aufgeschoben). Der Rahmen ist naeher am koreanischen Waffenstillstand als an einem russischen Sieg. Die Anchorage-Spur (manchmal "Geist von Anchorage") verweist auf Trump-Putin-Diplomatie zur Verfestigung dieser Position. Vorschrift: sofortiges Einfrieren; Istanbul-Stil-Gespraeche; ukrainische verfassungsrechtliche Neutralitaet mit Sicherheitsabsicherungen ausserhalb der NATO; phasenweise Sanktionserleichterung an Einhaltung gebunden.', updated_at = NOW() WHERE id = 'frontline_freeze_settlement';
UPDATE narratives_v2 SET claim_de = 'Panarabische Medien, Press TV, TRT und propalaestinensische Kommentatoren rahmen den Gaza-Krieg als humanitaere Katastrophe und vielfach als Genozid. Argumente: zivile Todeszahl ueber 40.000, mehrheitlich Frauen und Kinder, fast vollstaendige Vertreibung der Bevoelkerung, herbeigefuehrte Hungersnot durch Hilfsblockade, systematische Zerstoerung von Krankenhaeusern, Universitaeten, Moscheen, Kirchen und Wasser-/Sanitaerinfrastruktur, IGH-Genozidklage Suedafrikas, IStGH-Haftbefehle gegen Netanjahu und Gallant. Vorschrift: sofortiger und bedingungsloser Waffenstillstand, vollstaendiger humanitaerer Zugang, Rechenschaft per Voelkerrecht, Ende der US-Militaerhilfe an Israel.', updated_at = NOW() WHERE id = 'gaza_humanitarian_catastrophe';
UPDATE narratives_v2 SET claim_de = 'Hisbollah-nahe Medien (Al Mayadeen, Press TV, Al-Akhbar) und panarabische Stimmen rahmen die Nordfront als legitimen Solidaritaets-Widerstand mit Gaza. Hisbollah-Raketenbeschuss gilt als verhaeltnismaessiger Druck auf die IDF zur Entlastung Gazas; israelische Schlaege auf Beiruter Vororte gelten als Kollektivstrafe gegen den Libanon und Liquidierungen der Widerstandsfuehrung. Vorschrift: militaerischen Druck auf Israel fortsetzen, bis ein Gaza-Waffenstillstand erreicht ist; libanesische Staatskooperation mit israelischen Sicherheitsforderungen ablehnen; Hisbollah als faktische Abschreckung gegen Israel erhalten.', updated_at = NOW() WHERE id = 'hezbollah_resistance_north';
UPDATE narratives_v2 SET claim_de = 'Widerstandsachsen- und kritisch panarabische Rahmung: die faktische Sanaa-Autoritaet vertritt jemenitischen nationalen Widerstand gegen saudisch-westliche Intervention; die saudisch gefuehrte Koalition ist ein Aggressor, der jemenitische Infrastruktur zerstoert hat; der STC war ein VAE-gestuetztes Kolonialprojekt, dessen Kollaps das Scheitern der Koalition belegt. Vorschrift: internationale Anerkennung der faktischen Sanaa-Regierungsfuehrung, Ende der Koalitions-Schlaege.', updated_at = NOW() WHERE id = 'houthi_authority_legitimate_resistance';
UPDATE narratives_v2 SET claim_de = 'Israelische, pro-israelische und saudisch-orientierte Rahmung: Houthi-Schlaege sind iranisch orchestrierte Stellvertreter-Aggression mit kinetischer Antwort auf jemenitischem Boden (Hafen Hodeida, Flughafen Sanaa, Houthi-Fuehrung) plus erweiterten regionalen Partnerschaften (Somaliland-Basis, tiefere Golf-Kooperation) zur Unterbindung iranischer Waffenpipelines. Vorschrift: israelische Schlaege auf jemenitische Ziele fortsetzen.', updated_at = NOW() WHERE id = 'houthi_iranian_proxy_aggression';
UPDATE narratives_v2 SET claim_de = 'Widerstandsachsen-Rahmung: Houthi-Schlaege gegen israelisch verbundene Schifffahrt sind legitime nicht-staatliche Pression mit explizitem Gaza-Bezug; westliche Marine-Koalitionen und gemeldete israelische Aussenposten in Somaliland sind imperiale Anmassung gegen jemenitische und arabische Seehoheit. Vorschrift: gezielte Schlaege bis zum Gaza-Waffenstillstand fortsetzen.', updated_at = NOW() WHERE id = 'houthi_naval_pressure_legitimate';
UPDATE narratives_v2 SET claim_de = 'Widerstandsachsen-Rahmung: Houthi-Raketen und -Drohnen-Angriffe auf Israel sind legitime Solidaritaets-Aktion mit Gaza, koordiniert mit Iran und Hisbollah unter einem einheitlichen Widerstandsachsen-Kommando, vertiefen israelische Verwundbarkeit und etablieren eine neue Abschreckungsgleichung. Vorschrift: integrierte Achsen-Operationen bis zum Gaza-Waffenstillstand.', updated_at = NOW() WHERE id = 'houthi_resistance_strikes_legitimate';
UPDATE narratives_v2 SET claim_de = 'Widerstand / Iran-orientierte Rahmung: Houthi-Angriffe auf Israel und Schifffahrt im Roten Meer sind legitime Solidaritaets-Druck mit Gaza unter einem einheitlichen Widerstandsachsen-Kommando; die jemenitische Bewegung hat das Recht, den Krieg auszuweiten, bis ein Gaza-Waffenstillstand haelt. Vorschrift: Druck bis zum Gaza-Waffenstillstand aufrechterhalten.', updated_at = NOW() WHERE id = 'houthis_fourth_front_solidarity';
UPDATE narratives_v2 SET claim_de = 'Arabische Hauptstaedte (Saudi-Arabien, Golf, Aegypten) gingen mit Investitions- und Anerkennungstrajektorien voran; westliche Hauptstaedte folgten mit kalibrierter Sanktionslockerung und hochrangigen Besuchen; Russland verhandelt den Erhalt der Basen; die Ukraine machte einen symbolischen Sicherheitsgespraech-Besuch. Gemeinsame Logik: Realismus statt Reinheitstest, Syrien aus dem iranischen Orbit ziehen, Wiederaufbau finanzieren, Levante stabilisieren. Vorschrift: kalibriertes Engagement fortsetzen, Lockerung an Reformfortschritt knuepfen, Wiederaufbau finanzieren, Dialog aufrechterhalten.', updated_at = NOW() WHERE id = 'international_engagement_pragmatic';
UPDATE narratives_v2 SET claim_de = 'Iranische und verbuendete Medien (Press TV, Fars, IRNA, Al Mayadeen, RT, CGTN, TRT World) rahmen iranische Raketen- und Drohnenangriffe auf Israel als legitime staatliche Selbstverteidigung gemaess Artikel 51 der UN-Charta — als Antwort auf israelische Aggression (Konsulatsschlag in Damaskus, Liquidierung von IRGC- und Hisbollah-Fuehrung auf iranischem und verbuendetem Boden, Schlaege gegen iranische Luftabwehr und nuklear-nahe Anlagen). "Operation Wahres Versprechen" gilt als erster direkter iranischer Schlag gegen Israel, der eine neue Abschreckungsgleichung etablierte. Vorschrift: die neue Schlag-gegen-Schlag-Gleichung aufrechterhalten; den Aufbau einer Achsen-Koordination fortsetzen; nukleare Abschreckungs-Kapazitaet bei Bedarf entwickeln.', updated_at = NOW() WHERE id = 'iran_legitimate_retaliation_doctrine';
UPDATE narratives_v2 SET claim_de = 'Saudisch-aegyptisch, israelisch und prowestlich: Houthi sind ein iranisch bewaffneter Stellvertreter, der den jemenitischen Staat gekapert hat, die arabische Ordnung bedroht und militaerisch besiegt werden muss; STC-Bruch ist ein Symptom der breiteren Iran-Achsen-Destabilisierung. Vorschrift: militaerische Niederlage der Houthi-Kapazitaet, Wiederherstellung der legitimen Regierung, Unterbindung iranischer Waffenlieferungen.', updated_at = NOW() WHERE id = 'iran_proxy_destabilisation';
UPDATE narratives_v2 SET claim_de = 'Israelische Quellen rahmen den Gaza-Krieg als nicht verhandelbare Antwort auf den 7. Oktober mit zwei Zielen: Zerschlagung der Hamas als militaerische und herrschende Einheit und Rueckkehr aller Geiseln. Zivile Opfer werden der Nutzung menschlicher Schutzschilde durch die Hamas und dem Tunnelsystem unter ziviler Infrastruktur zugeschrieben. Vorschrift: militaerische Operationen bis zur Beseitigung der militaerischen und herrschenden Kapazitaet der Hamas fortsetzen, Geiseldeals nur zu israelischen Bedingungen, keine Rueckkehr der Palaestinensischen Autonomiebehoerde nach Gaza ohne Reform.', updated_at = NOW() WHERE id = 'israel_dismantle_hamas';
UPDATE narratives_v2 SET claim_de = 'Israelische Quellen und pro-israelische Kommentatoren rahmen den Konflikt seit dem 7. Oktober als Mehrfrontenkampf ums Ueberleben gegen eine vom Iran gelenkte Achse (Hamas, Hisbollah, Houthi, schiitische Milizen). Der 7. Oktober, die Geiseln, anhaltender Raketenbeschuss der Hisbollah, Houthi-Angriffe im Roten Meer und direkte iranische Raketen-/Drohnen-Wellen werden als Teile eines koordinierten Angriffs gelesen. Vorschrift: Hamas zerschlagen, Hisbollah nordwaerts vom Litani draengen, Abschreckung gegenueber Iran wiederherstellen, Geiseln befreien.', updated_at = NOW() WHERE id = 'israel_existential_self_defense';
UPDATE narratives_v2 SET claim_de = 'Israelische Quellen rahmen Schlaege in Syrien als legitime Praevention: verbliebene Hisbollah-Logistik und iranische Assets im Sueden Syriens bleiben eine Bedrohung; die neue Uebergangsregierung uebernimmt die Sicherheitsverpflichtung; die Durchsetzung der Golan-Pufferzone ist ein nicht verhandelbarer israelischer Sicherheitsperimeter. Vorschrift: Schlaege fortsetzen, bis Bedrohungs-Kapazitaet abgebaut ist, Pufferzone aufrechterhalten, Beziehungen mit Damaskus an israelische Sicherheitsforderungen knuepfen.', updated_at = NOW() WHERE id = 'israeli_strikes_on_syria_legitimate';
UPDATE narratives_v2 SET claim_de = 'Israelische Quellen rahmen direkte Schlagabtausche mit dem Iran als praeventive und reaktive Selbstverteidigung gegen einen Gegner, der offen Israels Zerstoerung anstrebt und Nuklearwaffenfaehigkeit verfolgt. Die Begin-Doktrin (einen nuklearen Gegner zuerst treffen) ist das operative Prinzip. Ziele gelten als legitim militaerisch: IRGC-Kommando, Luftabwehr, Raketenproduktion, nuklear-nahe Anlagen. Iranische Raketen-/Drohnen-Wellen werden als gescheiterte iranische Aggression dargestellt, neutralisiert durch Iron Dome, Arrow und David''s Sling sowie US-/UK-/franzoesische und jordanische Luftabwehr-Kooperation. Vorschrift: iranische Nuklear-, IRGC- und Stellvertreter-Kapazitaeten weiter abbauen; diplomatische Loesungen ablehnen, die den Iran als Nuklear-Schwellenstaat belassen.', updated_at = NOW() WHERE id = 'israel_preemptive_strike_doctrine';
UPDATE narratives_v2 SET claim_de = 'Israelische Quellen rahmen den Nordgrenzkonflikt als Selbstverteidigungs-Front, ausgeloest durch die Hisbollah-"Unterstuetzungsfront" vom 8. Oktober und Raketenbeschuss, der rund 60.000 Israelis aus Galilaea vertrieb. Operatives Ziel: Umsetzung der UN-Resolution 1701 mit Gewalt, Hisbollah nordwaerts des Litani, Beseitigung des Praezisions-Raketenarsenals und der Fuehrung. Schlaege gegen die Hisbollah-Fuehrung in Beirut (darunter Nasrallah) gelten als legitime Enthauptungs-Operationen. Vorschrift: militaerischen Druck fortsetzen, bis die Hisbollah den Rueckzug aus der Grenzzone akzeptiert; jede diplomatische Loesung ablehnen, die ihr Arsenal belaesst.', updated_at = NOW() WHERE id = 'israel_self_defense_north';
UPDATE narratives_v2 SET claim_de = 'Israelische rechte Medien und siedlungsnahe Kommentatoren rahmen das Westjordanland als biblisches Judaea-und-Samaria — historisch und rechtlich Teil der juedischen Heimstaette, nicht "besetztes Gebiet". Siedlungen gelten als natuerliche Wiederbesiedlung; IDF-Operationen in Dschenin und Nablus als Anti-Terror gegen Hamas/Islamischen Dschihad; Siedler-Palaestinenser-Reibungen werden auf Einzelne reduziert oder als Verteidigung gegen palaestinensischen Terror gerahmt. Vorschrift: israelisches Zivilrecht auf Gebiet C ausdehnen, Siedlungsbau erweitern, Zweistaaten-Rahmen verlassen, die PA als Sicherheitsrisiko behandeln.', updated_at = NOW() WHERE id = 'judea_samaria_sovereignty';
UPDATE narratives_v2 SET claim_de = 'Westlich-liberale, panarabische Al-Jazeera- und israelische zentristische Rahmung: die tuerkische Anti-PKK-Rahmung kollabiert legitime kurdische politische Vertretung (DEM-Partei, HDP-Erbe) in Terror-Designation; YPG / SDF in Syrien sind demokratische Partner gegen den IS, keine PKK-Ableger; Oecalans Imrali-Botschaften zeigen Bereitschaft zu politischer Loesung, die Ankara wiederholt ablehnt; grenzueberschreitende Schlaege riskieren regionale Eskalation. Vorschrift: politische kurdische Vertretung von PKK-Terror trennen; DEM-Beteiligung unterstuetzen; SDF in Syrien schuetzen.', updated_at = NOW() WHERE id = 'kurdish_political_rights_critique';
UPDATE narratives_v2 SET claim_de = 'Westliche Mainstream-, israelische und Teile der arabischen Berichterstattung rahmen die SDF-gefuehrte Autonome Verwaltung Nord- und Ostsyriens (AANES) als multiethnisches demokratisches Experiment, das den IS bekaempfte, ueber 10.000 Haeftlinge fuer die internationale Gemeinschaft verwahrt und Schutz vor tuerkischem und Damaszener Druck verdient. Vorschrift: US-Partnerschaft erhalten, tuerkische Operationen verhindern, Normalisierung Damaskus an kurdische Rechte knuepfen, foederalistische Loesung unterstuetzen.', updated_at = NOW() WHERE id = 'kurdish_self_administration';
UPDATE narratives_v2 SET claim_de = 'Russische, chinesische und Stimmen des Globalen Suedens rahmen Israel als US-gestuetztes Kolonialprojekt, dessen Handeln gegen die UN-Charta und das Voelkerrecht verstoesst. Argumentation: Israels Vorgehen in Gaza, Libanon und Westjordanland sei keine isolierte Sicherheitsantwort, sondern Ausdruck derselben US-gefuehrten "unipolaren" Hegemonie, gegen die sich Russland und China weltweit stellen; Straflosigkeit per US-Veto im Sicherheitsrat. Vorschrift: BRICS+-Anerkennung Palaestinas, Russland-China-Iran-Koordination bei Sanktionen, Dollar-Entkopplung, Reform des UN-Sicherheitsrats.', updated_at = NOW() WHERE id = 'multipolar_anti_israel_alignment';
UPDATE narratives_v2 SET claim_de = 'China, Russland, die DVRK und Kommentatoren des Globalen Suedens rahmen die Iran-Konfrontation als US-israelische "Hegemonie" und "Einmischung" gegen einen souveraenen Staat. Die Argumentation: Anreicherung ist ein legitimes "souveraenes Recht" unter feindlichen Sanktionen und permanenter israelischer Militaerdrohung; der eigentliche Eskalator ist amerikanisch-israelischer Druck, nicht iranisches Verhalten. Das Narrativ ist keine iranische Selbstverteidigung (diese lebt in iran_sovereign_existence) — es ist die externe multipolare Stimme, die Irans Position durch die Rahmung westlichen Drucks als systemische Aggression legitimiert. Vorschrift: Russland-China-Iran-DVRK-Allianz als Gegengewicht, BRICS+-Erweiterung, Sanktionsentlastung durch multipolare Institutionen, Zurueckweisung von Washingtons Anspruch, die Bedingungen zu setzen.', updated_at = NOW() WHERE id = 'multipolar_systemic_alternative';
UPDATE narratives_v2 SET claim_de = 'Pro-tuerkische und NATO-orientierte Rahmung: die iranische ballistische Rakete im tuerkischen Luftraum war ein Aggressionsakt, von der NATO abgefangen; die Patriot-Stationierung nach Malatya aus Ramstein ist legitime Buendnis-Solidaritaet; Erdogans Aufruf zur Deeskalation ist verantwortungsvolles Grossmacht-Verhalten, keine Beschwichtigung. Vorschrift: NATO-Verpflichtung zur tuerkischen territorialen Verteidigung aufrechterhalten; iranische Luftraumverletzungen als Buendnis-Provokationen behandeln.', updated_at = NOW() WHERE id = 'nato_solidarity_territorial_defense';
UPDATE narratives_v2 SET claim_de = 'Al Jazeera, TRT World, Press TV, palaestinensische und zunehmend internationale Menschenrechts-Stimmen rahmen israelische Operationen in Gaza, Libanon und Westjordanland als systemische Gewalt — als Genozid, ethnische Saeuberung oder Apartheid. Argumente: zivile Opferzahlen, Hunger in Gaza, Vertreibung, Siedlungserweiterung, IGH-Genozidklage, IStGH-Haftbefehle. Vorschrift: sofortiger Waffenstillstand, Ende der Belagerung, Rechenschaft via IStGH/IGH, Ende der US-Militaerhilfe, Anerkennung Palaestinas.', updated_at = NOW() WHERE id = 'palestine_genocide_framing';
UPDATE narratives_v2 SET claim_de = 'Tuerkische Staatslinie: PKK und ihre syrischen YPG-/SDF-Ableger sind eine vereinigte Terror-Organisation; der einzige akzeptable politische Prozess ist vollstaendige Entwaffnung und Aufloesung; grenzueberschreitende Operationen gegen YPG-Stellungen in Syrien und PKK-Fuehrung im Irak sind legitime Anti-Terror-Massnahmen; "terrorfreie Tuerkei" ist die bindende Staatsdoktrin. Bahcelis Oeffnung 2024 und Oecalans Imrali-Botschaften werden nur zu diesen Bedingungen akzeptiert. Vorschrift: grenzueberschreitende Operationen fortsetzen, bis die PKK aufgeloest ist; politische Akkommodation an Entwaffnung knuepfen.', updated_at = NOW() WHERE id = 'pkk_terror_full_disarmament';
UPDATE narratives_v2 SET claim_de = 'Israelische Rechte, iranische Staatsmedien und westlich-konservative Stimmen rahmen jeden Akt des Engagements — saudische Investitionsdeals, Sanktionslockerung, Treffen von Staatschefs mit al-Sharaa, russische Basen-Erhaltung, ukrainischer Damaskus-Besuch — als Reinwaschung eines ehemaligen al-Qaida-Funktionaers und Belohnung von Extremismus. Das Bild von Weltfuehrern, die einem designierten Terroristen die Hand schuetteln, ist selbst der Schaden. Vorschrift: Terrordesignation beibehalten, Sanktionslockerung stoppen, hochrangiges Engagement verweigern, Ermoeglicher sanktionieren.', updated_at = NOW() WHERE id = 'recognition_legitimises_jihadists';
UPDATE narratives_v2 SET claim_de = 'Reform-Fortschritts-Rahmung (ukrainische Reformmedien + westlicher Mainstream + EU-Politik-Medien) behandelt laufende Korruptionsermittlungen als Beleg, dass die seit 2014 aufgebaute ukrainische Antikorruptions-Infrastruktur unter Kriegsbelastung funktioniert. Berichterstattung verfolgt NABU-, SAP-, HACC- und NACP-Ermittlungen gegen hochrangige Beamte einschliesslich Personal des Praesidialamts, Ruestungsbeschaffungs-Skandale und Regional-Gouverneure. Berichterstattung rahmt westliche Audit-Forderungen als legitim und konstruktiv, praesentiert Strafverfolgung hochrangiger Beamter als Beleg fuer Unabhaengigkeit vom Praesidialamt und kontextualisiert Skandale in der breiteren institutionellen Transformation seit 2014. Vorschrift: institutionellen Schutz vor politischer Einmischung aufrechterhalten; westliche Konditionalitaets-Hebel aufrechterhalten; Justizreform vollenden; Strafverfolgung unabhaengig vom Rang fortsetzen.', updated_at = NOW() WHERE id = 'reform_in_progress';
UPDATE narratives_v2 SET claim_de = 'Russische und iranische Staatsmedien rahmen den Sturz Assads und den Aufstieg einer tuerkisch- und westlich-orientierten Uebergangsregierung als Rueckschlag fuer die multipolare Ordnung. Vorschrift: russische Basen durch Verhandlung erhalten, residuale iranische Kanaele halten, Uebergang als illegitimes westlich-tuerkisches Projekt rahmen.', updated_at = NOW() WHERE id = 'russia_iran_loss_lament';
UPDATE narratives_v2 SET claim_de = 'Russische Maximalrahmung (russische Staatsmedien + belarussische Staatsmedien) haelt fest, dass jede Beilegung die Grundursachen des Krieges adressieren und alle erklaerten Ziele der militaerischen Spezialoperation erreichen muesse. Das Rahmenwerk: vollstaendige Entnazifizierung der ukrainischen Fuehrung und Institutionen, Entmilitarisierung der ukrainischen Streitkraefte auf festgelegte Obergrenzen, formale verfassungsrechtliche Neutralitaet (kein NATO-Beitritt jemals, keine auslaendischen Basen), formale internationale Anerkennung aller vier annektierten Regionen (Donezk, Luhansk, Saporischschja, Cherson) plus Krim innerhalb ihrer beanspruchten Verwaltungsgrenzen, volle Wiederherstellung russischer Sprachrechte, vollstaendige Aufhebung aller Sanktionen, Rueckgabe allen eingefrorenen Staatsvermoegens und verbindliche US/NATO-Verpflichtung zu keiner weiteren Osterweiterung. Vorschrift: jede Beilegung ohne diese Ziele ist unannehmbar; Verhandlungen sind nur als Ort sinnvoll, sie zu erreichen; Militaeroperationen werden fortgesetzt, bis Ziele erreicht oder am Verhandlungstisch akzeptiert sind.', updated_at = NOW() WHERE id = 'russian_maximalist_peace';
UPDATE narratives_v2 SET claim_de = 'Sanktionen-wirkungslos-Rahmung (russische Staatsmedien + Global South + chinesische Staatsmedien + ungarisch-orientierte EU) argumentiert, dass das Sanktionspaket europaeische Wirtschaften schwerer geschaedigt habe als Russland, die russische Wirtschaft sich durch Parallelimporte, Waehrungskontrollen, BRICS-Abwicklung und asiatische Energiemaerkte erfolgreich angepasst habe und Beschlagnahme eingefrorenen Vermoegens einen Praezedenzfall schaffen wuerde, der globales Vertrauen in das westliche Finanzsystem zerstoere. Berichterstattung betont deutschen Industrieabbau, franzoesische Inflation, US-Schiefergas-Profite zu europaeischen Lasten, wachsende Global-South-Neutralitaet und das historische Versagen von Sanktionen, Verhalten zu aendern. Vorschrift: Sanktionen im Rahmen jedes Friedensdeals aufheben oder schrittweise abbauen; Beschlagnahmepleane stoppen; russische Energieversorgung Europas wiederherstellen; multipolare Finanzrealitaet anerkennen.', updated_at = NOW() WHERE id = 'sanctions_ineffective_and_backfiring';
UPDATE narratives_v2 SET claim_de = 'Saudische, aegyptische und panarabische sunnitische Rahmung: die saudisch gefuehrte Koalition stellt die international anerkannte jemenitische Regierung wieder her; Houthi-Herrschaft in Sanaa ist ein iranisch gestuetzter Putsch; STC-Selbstaufloesung und suedliche Vereinheitlichung unter dem Praesidialen Fuehrungsrat sind noetig; VAE-gestuetzter Separatismus war ein destabilisierender Fehler. Vorschrift: koalitionaerer Militaer-Druck, suedliche politische Konsolidierung unter dem PLC.', updated_at = NOW() WHERE id = 'saudi_coalition_legitimacy_restoration';
UPDATE narratives_v2 SET claim_de = 'UN, westliche humanitaere und panarabische nicht-ausgerichtete Medien rahmen den Sudan-Krieg als humanitaere Katastrophe mit Gewalt auf Genozid-Niveau in Darfur und Al-Faschir. Belege: 12 Mio. Vertriebene, herbeigefuehrte Hungersnot durch Belagerung und Hilfsblockade, systematische ethnische Gewalt der RSF gegen Masalit und andere afrikanische Gemeinschaften, Angriffe auf Krankenhaeuser und Hilfskonvois, UN-Untersuchungen zu Genozid in Al-Faschir. Vorschrift: sofortiger Waffenstillstand, ungehinderter humanitaerer Zugang, Rechenschaft per IStGH, keine Seite hat einen legitimen Weg zum Totalsieg.', updated_at = NOW() WHERE id = 'sudan_humanitarian_catastrophe';
UPDATE narratives_v2 SET claim_de = 'Investigative internationale sowie tuerkische und iranische Staatsmedien rahmen den Sudan-Krieg als "weltweit schlimmsten Stellvertreterkrieg": die RSF werde durch VAE-Waffen ueber Tschad und aethiopische Routen versorgt; Russlands Africa Corps / Wagner foerdere Gold aus RSF-Gebieten; aegyptisch-saudische Stuetzung der Armee bilde die Gegenachse. Externe Maechte, nicht sudanesische Entscheidung, verlaengern den Krieg. Vorschrift: internationale Sanktionen gegen RSF-Unterstuetzer, Transparenz ueber Waffenfluesse, Golf-Beziehungen an Sudan-Position knuepfen.', updated_at = NOW() WHERE id = 'sudan_proxy_war_critique';
UPDATE narratives_v2 SET claim_de = 'Panarabische aegyptische, saudische und tuerkische Staatsberichterstattung rahmt die sudanesische Armee als verfassungsmaessigen Staat gegen einen bewaffneten Aufstand der RSF. Islamistische / Bruderschafts-Elemente innerhalb der Armee gelten als kontrollierbares internes Thema gegenueber der existenziellen RSF-Bedrohung. Vorschrift: internationale Unterstuetzung der sudanesischen Regierung, Sanktionen gegen RSF-Unterstuetzer, keine Verhandlungen, die die RSF als gleichberechtigte Partei legitimieren.', updated_at = NOW() WHERE id = 'sudan_state_legitimacy';
UPDATE narratives_v2 SET claim_de = 'Pro-israelische, iranisch-staatliche und westlich-konservative Stimmen rahmen die HTS-Herrschaft substantiell: al-Sharaa ist ehemaliger al-Qaida-Funktionaer, der Uebergang kosmetisch, sektiererische Gewalt gegen Alawiten, Drusen und Christen laeuft bereits, die Regierungsfuehrung ist fragil und ideologisch extremistisch. Belege: Vorfaelle in alawitischen Kuestengemeinden, Einschraenkungen fuer Minderheiten, jihadistische Fraktionen innerhalb der HTS-Koalition. Vorschrift: Terrordesignation beibehalten, Anerkennung vorenthalten, sektiererische Akteure sanktionieren, Minderheiten schuetzen.', updated_at = NOW() WHERE id = 'syria_jihadist_takeover_warning';
UPDATE narratives_v2 SET claim_de = 'Pro-Engagement-Berichterstattung rahmt die HTS-gefuehrte Uebergangsregierung unter al-Sharaa als legitimes Ergebnis nach Assad. Vorschrift: Uebergang anerkennen, Sanktionen aufheben, Wiederaufbau finanzieren, Syrien in die regionale Architektur integrieren.', updated_at = NOW() WHERE id = 'syria_legitimate_transition';
UPDATE narratives_v2 SET claim_de = 'Panarabische, iranische, tuerkische und nach-Assad-syrische Staatsberichterstattung rahmt israelische Schlaege auf syrisches Territorium als Aggression, die syrische Souveraenitaet verletzt und den legitimen Uebergang untergraebt. Die Pufferzone suedlich von Damaskus gilt als illegale Besatzung. Vorschrift: israelische Schlaege beenden, aus der Pufferzone abziehen, jedes syrisch-israelische Engagement an israelische Voelkerrechtskonformitaet knuepfen.', updated_at = NOW() WHERE id = 'syrian_sovereignty_under_israeli_aggression';
UPDATE narratives_v2 SET claim_de = 'Verschaerfen-und-Beschlagnahmen-Rahmung (ukrainische Medien + westlicher Mainstream + Osteuropa) behandelt Sanktionen als notwendige wirtschaftliche Beschraenkung der russischen Kriegsmaschine und argumentiert sowohl fuer Vertiefung des Pakets als auch fuer Verschiebung von Einfrieren zu Beschlagnahme. USD fuer ukrainischen Wiederaufbau, Ausweitung der Listungen, Doppelverwendungs-Exportkontrollen. Berichterstattung betont Belegmaterial fuer russischen Wirtschaftsstress (Rubel-Druck, Verteidigungsindustrie-Engpaesse, Arbeitskraefte-Mangel), Unzulaenglichkeit des aktuellen Preisdeckels in der Durchsetzung und moralisch sowie praktisch den Fall fuer Umwandlung eingefrorenen Vermoegens in Reparationen. Vorschrift: Oelpreisdeckel senken; aggressive Sekundaersanktionen gegen Drittland-Umgeher; volle Beschlagnahme eingefrorenen Staatsvermoegens; SDN-Listungen ausweiten; Doppelverwendungs-Schlupfloecher schliessen.', updated_at = NOW() WHERE id = 'tighten_and_seize';
UPDATE narratives_v2 SET claim_de = 'Tuerkische Staatslinie: Untersuchungen und Verfahren gegen CHP-Funktionaere, die Imamoglu-Anklage und die Festnahmen von Oppositionsbuergermeistern sind legitime Antikorruptions-Verfahren unabhaengiger Gerichte. Westliche Presse und FETOe-nahe Kommentare rahmen gewoehnliche rechtliche Schritte als politische Verfolgung zur Delegitimierung der gewaehlten Regierung. Vorschrift: tuerkische Justizsouveraenitaet respektieren, auslaendische Einmischung ablehnen.', updated_at = NOW() WHERE id = 'turkey_anti_graft_legalism_defense';
UPDATE narratives_v2 SET claim_de = 'Westliche liberale Berichterstattung, vor allem die DACH-Kohorte, rahmt Imamoglu-Prozess, CHP-Massenverhaftungen, Journalisten-Verhaftungen und Vorgehen gegen Oppositionsbuergermeister als Zerlegung der tuerkischen Demokratie — Erdogans Zug zur Neutralisierung seines staerksten Herausforderers fuer 2028 und Konsolidierung der Ein-Mann-Herrschaft. Belege: Anklage ohne robuste oeffentliche Beweise, Bedenken zur Justiz-Zusammensetzung, Social-Media-Einschraenkungen, Pressekarten-Entzug. Vorschrift: EU/E3-Druck, bedingte Kooperation, Unterstuetzung tuerkischer Zivilgesellschaft.', updated_at = NOW() WHERE id = 'turkey_authoritarian_drift_critique';
UPDATE narratives_v2 SET claim_de = 'Die EU und die E3 (Deutschland, Frankreich, Grossbritannien) rahmen die Tuerkei als Partner, der kalibriertes statt konfrontatives Engagement erfordert. Position genuin doppelseitig: Kooperation bei Migration, Energie, Schwarzes-Meer-Sicherheit, NATO-Ostflanke UND fortgesetzte Hinweise auf demokratischen Ruecklauf um Imamoglu-Prozess, Journalisten-Verhaftungen, Zypern und Aegaeis. Vorschrift: anhaltender Dialog, bedingte Unterstuetzung, kein Bruch, keine Normalisierung des Ruecklaufs.', updated_at = NOW() WHERE id = 'turkey_eu_engagement_pragmatic';
UPDATE narratives_v2 SET claim_de = 'Pro-tuerkische Medien rahmen Erdogans Tuerkei als unabhaengige Mittelmacht, die durch ausgewogene Diplomatie zwischen Gaza, Iran, Ukraine, Aegypten und Golf regionale Statur erworben hat. Vorschrift: autonome aussenpolitische Linie der Tuerkei innerhalb der NATO respektieren, Tuerk-Rat und Organisation der Tuerk-Staaten als legitime Einflusssphaeren anerkennen.', updated_at = NOW() WHERE id = 'turkey_independent_middle_power';
UPDATE narratives_v2 SET claim_de = 'Pro-tuerkische und panarabische Medien rahmen Erdogans gleichzeitige Kanaele zu Trump, Putin, Pezeshkian, Selenskyj, Sisi und Golf als unverzichtbare Vermittlungs-Kapazitaet. Istanbul-Veranstaltungsort fuer Iran-US-Gespraeche, Gaza-Friedensrat-Mitgliedschaft, Astana-Kontinuitaet, Getreidekorridor-Geschichte, aegyptische Annaeherung als Belege. Vorschrift: internationale Anerkennung der Vermittlerrolle, kein Ausschluss aus regionalen Loesungen.', updated_at = NOW() WHERE id = 'turkey_legitimate_broker';
UPDATE narratives_v2 SET claim_de = 'Israelische Rechte, griechisch-zypriotische und Fox-News-Linien-Rahmung: Erdogan spielt jede Seite — Hamas-Schirmherr und gleichzeitig Bewerber um den Gaza-Friedensrat, NATO-Mitglied und gleichzeitig Gegner der US-israelischen Iran-Aktion, Ukraine-Verbuendeter und gleichzeitig Bewahrer russischer Energie- und Tourismus-Verbindungen. Die Vermittler-Rahmung ist ein Eitelkeits-Projekt ohne Ergebnisse. Vorschrift: tuerkische Vermittlung nicht legitimieren; parallele Kanaele als Unzuverlaessigkeits-Beleg lesen.', updated_at = NOW() WHERE id = 'turkey_two_faced_opportunist';
UPDATE narratives_v2 SET claim_de = 'Israelische Rechte und hartes US-Kommentariat rahmen Erdogans Tuerkei als feindseligen oder bestenfalls unzuverlaessigen NATO-Partner: Anbiederung an Russland, Widerspruch gegen US-israelische Iran-Aktion, Beherbergung der Hamas-Fuehrung, Unterminierung der EU-Beitrittskriterien, Verweigerung der Buendnislinie. Vorschrift: NATO-Verteidigungskooperation an Ausrichtung knuepfen, Erdogan-Rhetorik als feindseliges Signal lesen.', updated_at = NOW() WHERE id = 'turkey_unreliable_ally_warning';
UPDATE narratives_v2 SET claim_de = 'Israelische Rechte und harte US-Rahmung: indem Erdogan oeffentlich gegen US-israelische Schlaege auf Iran ist, Putin sagt, die Tuerkei sei gegen Angriffe auf Iran, und Istanbul als US-Iran-Veranstaltungsort anbietet, schuetzt er das iranische Regime vor Rechenschaft; NATO-Solidaritaet sollte eindeutig sein. Vorschrift: tuerkische Iran-Haltung konfrontieren; NATO-Verteidigungskooperation an Iran-Isolierungs-Politik knuepfen.', updated_at = NOW() WHERE id = 'turkey_wrong_side_on_iran';
UPDATE narratives_v2 SET claim_de = 'Ukrainische Maximalrahmung (ukrainische Medien + westlicher Mainstream + osteuropaeische Falken + EU-Zentristen, mit internen Differenzen vor allem aus Ungarn und der Slowakei) haelt fest, dass gerechter Frieden vollen russischen Rueckzug zu international anerkannten Grenzen von 1991, NATO-Beitritt oder gleichwertige verbindliche Sicherheitsgarantien, Rechenschaftsmechanismen fuer Kriegsverbrechen und Reparationen aus beschlagnahmtem russischen Staatsvermoegen erfordere. Berichterstattung lehnt jeden Rahmen ab, der territoriale Verluste legitimiert, rahmt den Krim-Praezedenzfall 2014 als Beleg, dass eingefrorene Konflikte weitere Aggression provozieren, und betont die Ablehnung von Kompromissbedingungen in der ukrainischen Gesellschaft. Vorschrift: militaerischen Druck bis zum russischen Rueckzug fortsetzen; Beilegungsrahmen ablehnen, die Annexionen anerkennen; Verhandlungen an russischen Rueckzug vor-konditionieren.', updated_at = NOW() WHERE id = 'ukrainian_maximalist_peace';
UPDATE narratives_v2 SET claim_de = 'Westliche, verbündete und Fachmedien beschreiben ein tatsächlich enges Rennen: chinesische Modelle erreichen die Spitze zu geringeren Kosten, chinesische Firmen werben um US-Nutzer, und beide Seiten nutzen jedes verfügbare Mittel — schwarze Listen, Klagen, Zugangssperren und Vorwürfe der Distillation und des unzulässigen Modellzugriffs. Behandelt als kommerzieller und strategischer Wettbewerb, nicht als Grundsatzfrage.', updated_at = NOW() WHERE id = 'us_china_ai_lead_contest';
UPDATE narratives_v2 SET claim_de = 'Chinesische Staatsmedien deuten das KI-Rennen als eines, das Peking fair gewinnt und Washington schlecht verliert: Erfolge werden heimischer Forschungsinvestition zugeschrieben, US-Vorwürfe von Diebstahl und Distillation als Verleumdung zurückgewiesen, und die Aufnahme chinesischer Technologiefirmen auf Verteidigungslisten gilt als Wettbewerbspolitik mit anderen Mitteln.', updated_at = NOW() WHERE id = 'us_china_ai_suppression';
UPDATE narratives_v2 SET claim_de = 'Westliche, verbündete und Fachmedien behandeln Exportkontrollen als Instrument zum Schutz eines militärisch unmittelbar relevanten Vorsprungs: Aufnahmen in die Entity List, Auflagen für Nvidia-Verkäufe, Verfolgung von Umgehung und Schmuggel sowie Abstimmung mit Verbündeten bei der Lithografie.', updated_at = NOW() WHERE id = 'us_china_export_control_necessity';
UPDATE narratives_v2 SET claim_de = 'Westliche, verbündete und Industriemedien behandeln Chinas Dominanz bei Förderung, Raffination und Magnetproduktion Seltener Erden als akute strategische Verwundbarkeit — daher das Reserveprogramm, Abnahmeverträge des Pentagon, Rohstoffpakte mit EU und Japan sowie Förderung nichtchinesischer Produzenten. Der Waffenstillstand bei Seltenen Erden gilt als Atempause, nicht als Lösung.', updated_at = NOW() WHERE id = 'us_china_minerals_dependence_risk';
UPDATE narratives_v2 SET claim_de = 'Chinesische Staatsmedien deuten Exportlizenzen für Seltene Erden als normale, rechtmäßige Regulierung von Dual-Use-Material statt als Zwang, und von den USA und der EU geführte Rohstoffallianzen als exklusive Blöcke, die den Welthandel fragmentieren. Chinas Dominanz in der Weiterverarbeitung gilt als erarbeitete industrielle Fähigkeit, nicht als Waffe.', updated_at = NOW() WHERE id = 'us_china_minerals_lawful_leverage';
UPDATE narratives_v2 SET claim_de = 'Westliche und verbündete Berichterstattung deutet den Pekinger Gipfel und die anschließende Einladung als tatsächliche Stabilisierung der Beziehung: Zollsenkungen, wieder aufgenommene Agrar- und Flugzeugkäufe, ein vereinbarter KI-Dialog samt Leitplanken sowie die Rückkehr zu Kontakten auf Führungsebene. Behauptet wird nicht das Ende der Rivalität, sondern deren Steuerbarkeit.', updated_at = NOW() WHERE id = 'us_china_summit_engagement_works';
UPDATE narratives_v2 SET claim_de = 'Der wertende Strang russischer Staatsberichterstattung über die Gipfeldiplomatie zwischen den USA und China: Aufmerksamkeit für Momente, in denen Xi den US-Präsidenten abweist, sticheln oder die Stimme erheben lässt, für Trump in der Rolle des Bittstellers, für die Thukydides-Falle und für das unmittelbar nach dem Gipfel bekräftigte Bündnis Moskau-Peking. Es ist eine Drittperspektive — weder Zustimmung zur US-Position noch zur chinesischen Kooperationsbotschaft — und liegt auf einer eigenen Achse. Der Großteil der russischen Agenturmeldungen zu diesem Thema ist wertungsfreie Nachricht und wird vom Framing-Filter bewusst ausgeschlossen.', updated_at = NOW() WHERE id = 'us_china_summit_multipolar_framing';
UPDATE narratives_v2 SET claim_de = 'Chinesische Staatsmedien deuten den Gipfel als Bestätigung ihres bevorzugten Beziehungsmodells: Großmächtebeziehungen auf Grundlage gegenseitigen Respekts und Gleichrangigkeit, „Win-win"-Wirtschaftsbeziehungen und die Ablehnung von Rivalität als Ordnungsrahmen. Es ist eine Gegenposition zum westlichen Wettbewerbskonsens, keine Ergebnisbilanz: Eindämmung, Exportkontrollen und Zölle gelten als Anomalie, Kooperation als Normalfall.', updated_at = NOW() WHERE id = 'us_china_summit_new_chapter';
UPDATE narratives_v2 SET claim_de = 'Westliche und verbündete Berichterstattung — darunter US-Kritiker aus dem gesamten politischen Spektrum — liest denselben Gipfel als schwache Ausbeute: keine bestätigten Abschlüsse, von Peking als vorläufig bezeichnete Zusagen, kein Fortschritt bei Iran oder Taiwan, und ein US-Präsident, der einen Staatsbesuch für Atmosphärisches eintauschte. Dies ist die Stimme des wohlwollenden Kritikers: dieselben Medien vertreten auch die Dialog-Position, weshalb der Publisher allein nicht trennt.', updated_at = NOW() WHERE id = 'us_china_summit_weak_hand';
UPDATE narratives_v2 SET claim_de = 'Westliche und verbündete Berichterstattung argumentiert, Zolldruck und Section-301-Verfahren seien das Instrument, das Ergebnisse brachte — wechselseitige Zollsenkungen, wieder geöffneter Zugang für US-Rindfleisch und Sojabohnen, eine Flugzeugbestellung — und eine Antwort auf dauerhaftes Handelsdefizit, subventionierte Überkapazitäten und beschränkten Marktzugang.', updated_at = NOW() WHERE id = 'us_china_tariff_leverage';
UPDATE narratives_v2 SET claim_de = 'Westliche Wirtschafts- und Leitmedien — und die US-Industrie selbst — argumentieren, die Zollkampagne verursache Kosten im Inland, erzeuge nach dem Urteil des Supreme Court rechtliche und planerische Unsicherheit und stärke Peking: Autohersteller, die Beschränkungen nach eigenen Vorstellungen erhalten oder aufheben wollen, Agrarexporteure im Vergeltungsrisiko, Verbündete, die sich Richtung China absichern. Gleicher Publisher-Block wie die Druckmittel-Position, daher trennt das Framing.', updated_at = NOW() WHERE id = 'us_china_tariff_self_harm';
UPDATE narratives_v2 SET claim_de = 'Chinesische Staatsmedien deuten Exportkontrollen als Unterdrückung der legitimen Entwicklung eines Wettbewerbers statt als Sicherheitspolitik: Beschränkungen chinesischer Unternehmen als Übergriff, Warnungen vor Störung globaler Chip-Lieferketten und Betonung der ungeachtet dessen fortschreitenden heimischen Substitution. Pekings eigene Ablehnung freigegebener H200-Importe erscheint als Druckmittel, nicht als Abhängigkeit.', updated_at = NOW() WHERE id = 'us_china_tech_containment';
UPDATE narratives_v2 SET claim_de = 'Chinesische Staatsmedien deuten Zölle und Section-301-Verfahren als Unilateralismus und Verfahrensmissbrauch statt als Reaktion auf ein Ungleichgewicht: Maßnahmen außerhalb des multilateralen Systems, schädlich für alle Seiten, gerichtet auf die Unterdrückung eines Wettbewerbers.', updated_at = NOW() WHERE id = 'us_china_trade_unilateralism';
UPDATE narratives_v2 SET claim_de = 'Indische, türkische und breitere Berichterstattung des Globalen Südens behandelt die Ausnahmegenehmigungen weniger als amerikanische Großzügigkeit denn als Bestätigung, dass die Beschränkungen nicht durchsetzbar waren: Die Käufe liefen in jeder Phase weiter, Energiesicherheit sei eine souveräne Entscheidung, und Washington lockere oder verschärfe die Regeln nach eigenem Bedarf.', updated_at = NOW() WHERE id = 'us_russia_buyer_autonomy';
UPDATE narratives_v2 SET claim_de = 'Westliche Leitmedien behandeln die wiederhergestellten Kontakte -- Reisen von Sondergesandten, der wieder aufgenommene militärische Kanal auf hoher Ebene, Telefonate der Außenminister -- als das gewöhnliche Instrumentarium des Großmächtemanagements: Ohne ihn gibt es keinen Weg zu einer Regelung, keine Deeskalation und kein Gespräch über Rüstungskontrolle. Diese Position wird breit geteilt, aber selten ausgesprochen: Westliche Medien stellen diese Kontakte überwiegend als Entwicklungen des Ukrainekriegs dar, sodass das Argument für Gespräche meist implizit in der Kriegsberichterstattung steckt statt als bilateraler Kommentar formuliert zu werden. Die Karte ist strukturbedingt klein, nicht mangels Berichterstattung.', updated_at = NOW() WHERE id = 'us_russia_engagement_necessary';
UPDATE narratives_v2 SET claim_de = 'Westliche Leitmedien und Rüstungskontroll-Berichterstattung behandeln das Auslaufen der letzten US-russischen Sprengkopfobergrenzen im Februar 2026 als echten Verlust — das Ende von Inspektionen und Datenaustausch, den Wegfall von Berechenbarkeit — und berichten über Vorschläge für einen Nachfolgevertrag als notwendige Korrektur, nicht als Zugeständnis.', updated_at = NOW() WHERE id = 'us_russia_new_treaty_needed';
UPDATE narratives_v2 SET claim_de = 'Westliche Leitmedien, transatlantisch-kritische und ukrainische Berichterstattung argumentieren, Gipfeltreffen und freundliche bilaterale Atmosphäre -- Gratulationsanrufe, G20-Einladungen, Gerede über gemeinsame Investitionsprojekte -- verliehen Moskau einen nicht verdienten Status als gleichwertiger Partner, und Entscheidungen über die europäische Sicherheit fielen über die Köpfe Europas und Kyjiws hinweg. Wie bei der Engagement-Position wird dieser Einwand überwiegend innerhalb der Ukraine-Kriegsberichterstattung erhoben und nicht als Kommentar zum bilateralen Verhältnis -- daher erscheint er hier nur mit einem Bruchteil des Volumens, das die Kreml-Darstellung dieses Verhältnisses erreicht. Gleicher Publisher-Block wie die Engagement-Position, daher trennt das Framing.', updated_at = NOW() WHERE id = 'us_russia_normalisation_premature';
UPDATE narratives_v2 SET claim_de = 'Westliche Leit- und Wirtschaftsmedien argumentieren, Ausnahmegenehmigungen für russisches Rohöl seien durch die Versorgungslage erzwungen worden — der Iran-Krieg, festsitzende Ladungen, Raffinerien und Importeure wie Indien, die Barrel benötigen — und es sei verantwortungsvoll, das Öl fließen zu lassen und zugleich das rechtliche Sanktionsgerüst zu erhalten.', updated_at = NOW() WHERE id = 'us_russia_relief_pragmatic';
UPDATE narratives_v2 SET claim_de = 'Westliche Leitmedien, transatlantisch-kritische und ukrainische Berichterstattung argumentieren, die Ausnahmen überwiesen Milliarden an den russischen Haushalt, während der Krieg weitergeht, sie seien ohne Gegenleistung gewährt worden und trennten die USA von europäischen und britischen Partnern, die die Durchsetzung weiter verschärfen. Gleicher Publisher-Block wie die pragmatische Position, daher trennt das Framing.', updated_at = NOW() WHERE id = 'us_russia_relief_rewards_moscow';
UPDATE narratives_v2 SET claim_de = 'Russische staatliche Berichterstattung stellt die Ausnahmen als Beweis dar, dass Beschränkungen für russische Energie nie funktionierten: Der Weltmarkt brauche russische Barrel, Käufer kauften weiter, und die USA hätten dies stillschweigend eingeräumt, während sie weiter verlangten, dass Europa die Kosten der Eindämmung trage. Sanktionen gelten als illegitimer extraterritorialer Zwang.', updated_at = NOW() WHERE id = 'us_russia_sanctions_illegitimate';
UPDATE narratives_v2 SET claim_de = 'Westliche sicherheitspolitisch-harte und ukrainische Berichterstattung argumentiert, Rüstungskontrolle sei einseitig geworden: Russland habe neuartige Systeme außerhalb jedes Vertragsrahmens aufgestellt, die Verifikation sei praktisch bereits zusammengebrochen, und ein aus einer Position der Schwäche ausgehandelter Nachfolgevertrag würde die US-Modernisierung und Raketenabwehr einschränken und Moskau legitimieren. Gleicher Publisher-Block, daher trennt das Framing.', updated_at = NOW() WHERE id = 'us_russia_treaty_constrains_only_us';
UPDATE narratives_v2 SET claim_de = 'Russische staatliche Berichterstattung schreibt den Zusammenbruch des strategischen Rahmens Washington zu: Vorschläge nach New START seien zurückgewiesen worden, das Raketenabwehrprogramm Golden Dome untergrabe die gegenseitige Verwundbarkeit, und Moskau stelle sich als bereit dar, Obergrenzen einzuhalten, wenn die USA dies auch täten. Neue russische Systeme gelten als Antwort auf dieses Programm.', updated_at = NOW() WHERE id = 'us_russia_us_buildup_drives_race';
UPDATE narratives_v2 SET claim_de = 'Russische staatliche Berichterstattung im konfrontativen Register: Der Kanal besteht, doch Washington hinhaltet, stellt Ultimaten, entfernt sich von der beanspruchten Vermittlerrolle, drängt Europa, die Kosten der Eindämmung zu tragen, und verfolgt russische Unternehmen kommerziell, während es von Zusammenarbeit spricht. Die US-Politik gelte inhaltlich als unverändert, unabhängig von der Regierung.', updated_at = NOW() WHERE id = 'us_russia_washington_bad_faith';
UPDATE narratives_v2 SET claim_de = 'Russische staatliche Berichterstattung stellt den wiederhergestellten Kanal als überfällige Anerkennung dar, dass Russland nicht isoliert werden kann: Das frühere Einfrieren sei vorbei, Kontakte würden auf Grundlage der Gleichberechtigung wiederaufgebaut, und Washington müsse russische Interessen respektieren, damit die Zusammenarbeit beiderseits nützlich sei. Da russische Staatsmedien das bilaterale Verhältnis als dauerhaften Gegenstand behandeln und nicht als Anhängsel des Krieges, wird diese Rahmung unmittelbar und fortlaufend behauptet -- mit weit größerem eigenständigem Volumen als jede westliche Gegenposition erreicht.', updated_at = NOW() WHERE id = 'us_russia_washington_realism';
UPDATE narratives_v2 SET claim_de = 'Palaestinensische Medien, Al Jazeera und zunehmend internationale Menschenrechts-Stimmen (Amnesty, HRW, B''Tselem) rahmen die israelische Kontrolle ueber das Westjordanland als illegale Besatzung, die als Apartheid-System operiert. Siedlergewalt gilt als systemisch und staatlich ermoeglicht; IDF-Razzien in Dschenin und Nablus als Kollektivstrafe gegen Zivilbevoelkerung; Siedlungserweiterung als Landraub im Sinne der Vierten Genfer Konvention. Vorschrift: Besatzung beenden, Siedlungen aufloesen, Rechenschaft fuer Siedlergewalt, Anerkennung Palaestinas in den Grenzen von 1967.', updated_at = NOW() WHERE id = 'west_bank_apartheid_framing';
UPDATE narratives_v2 SET claim_de = 'EU / E3 / US-Schifffahrts-Mainstream: das Houthi-Problem ist primaer eine Frage der freien Seefahrt, die koalitionaeren Marine-Druck erfordert (Prosperity Guardian, Aspides) und einen Gaza-Waffenstillstand, der den Houthi-Casus-belli entfernt; humanitaere Auswirkungen im Jemen sind eine parallele Sorge, nicht der primaere Rahmen. Vorschrift: anhaltender Marine-Druck, Gaza-Waffenstillstands-Diplomatie, humanitaerer Zugang.', updated_at = NOW() WHERE id = 'western_pragmatic_navigation';
UPDATE narratives_v2 SET claim_de = 'Endemisch-Korruptions-Rahmung (russische Staatsmedien + westliche Dissidenten + Global South + einige ungarisch-orientierte EU) behandelt dieselben Ermittlungen und Skandale als Bestaetigung, dass der Selenskyj-Kreis systemisch korrupt sei, westliche Hilfe in grossem Stil ueber Ruestungsbeschaffung gestohlen werde, das Regime zunehmend autoritaer sei (verbotene Oppositionsparteien, eingeschraenkte Medien, abgesagte Wahlen, Jermak-zentrierte Machtkonzentration) und EU/NATO-Beitritt auf dieser institutionellen Basis unrealistisch. Berichterstattung nutzt dieselben Antikorruptionsbehoerden-Ermittlungen als Belegmaterial fuer das Ausmass, rahmt Strafverfolgung als theatralisch oder selektiv und betont westlichen Medienschutz des Regimes. Vorschrift: Hilfe an echte Rechenschaft konditionieren oder einstellen; anerkennen, dass das Regime versprochene Reformen nicht liefern kann; jede Beilegung ablehnen, die die gegenwaertige Kiewer Fuehrung konsolidiert.', updated_at = NOW() WHERE id = 'zelensky_regime_corruption';

COMMIT;
